import asyncio
import websockets
from collections import defaultdict

class Inventory:
    def __init__(self):
        self.items = defaultdict(int)

    async def add_item(self, item_id, quantity):
        self.items[item_id] += quantity

    async def remove_item(self, item_id, quantity):
        if self.items[item_id] >= quantity:
            self.items[item_id] -= quantity
            return True
        return False

class GameServer:
    def __init__(self):
        self.clients = set()
        self.inventory = Inventory()

    async def register_client(self, websocket):
        self.clients.add(websocket)

    async def unregister_client(self, websocket):
        self.clients.remove(websocket)

    async def handle_trade_request(self, websocket, request):
        sender_id, receiver_id, item_id, quantity = request
        if await self.inventory.remove_item(item_id, quantity):
            await self.inventory.add_item(item_id, quantity)
            for client in self.clients:
                if client != websocket:
                    await client.send(f"TRADE_SUCCESS:{sender_id}:{receiver_id}:{item_id}:{quantity}")

    async def handle_message(self, websocket, message):
        request = message.split(':')
        command = request[0]
        if command == "REGISTER":
            await self.register_client(websocket)
        elif command == "UNREGISTER":
            await self.unregister_client(websocket)
        elif command == "TRADE_REQUEST":
            await self.handle_trade_request(websocket, request[1:])

    async def start(self):
        async with websockets.serve(self.handle_message, "localhost", 8765):
            await asyncio.Future()  # run forever

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.start())